import React, { useState, useEffect, useContext } from "react";
import { useParams, useNavigate } from "react-router-dom";
import AuthContext from "../context/AuthContext";
import axios from 'axios';
import "./CAProfile.css";

function CAProfile() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useContext(AuthContext);
    const [ca, setCa] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchCA();
    }, [id]);

    const fetchCA = async () => {
        try {
            const response = await axios.get(`http://localhost:5001/api/ca/${id}`);
            setCa(response.data);
        } catch (error) {
            console.error("Error fetching CA:", error);
        } finally {
            setLoading(false);
        }
    };

    const handleChat = () => {
        if (!user) {
            alert("Please login to chat with this CA");
            navigate("/login");
            return;
        }

        if (!user.isSubscribed && user.role === "user") {
            const confirmSub = window.confirm("You need a subscription to chat with CAs. Go to Subscription page?");
            if (confirmSub) {
                navigate("/subscription");
            }
            return;
        }

        if (!ca.userId) {
            alert("This CA is not available for chat (No linked account).");
            return;
        }

        navigate(`/chat/${ca.userId}`, { state: { caName: ca.name } });
    };

    if (loading) return <div className="container">Loading profile...</div>;
    if (!ca) return <div className="container">CA not found</div>;

    return (
        <div className="container ca-profile-page">
            <button className="btn-back" onClick={() => navigate(-1)}>&larr; Back to experts</button>

            <div className="profile-layout">
                <div className="profile-main">
                    <div className="profile-header card">
                        <div className="profile-cover" style={{ backgroundImage: `url(${ca.image || 'https://via.placeholder.com/800x300'})` }}></div>
                        <div className="profile-header-content">
                            <div className="profile-avatar-large">
                                {ca.name.charAt(0)}
                            </div>
                            <div className="profile-title">
                                <h1>{ca.name}</h1>
                                <p className="specialization">{ca.specialization}</p>
                                <div className="profile-meta">
                                    <span>📍 {ca.location}</span>
                                    <span>💼 {ca.experience} Experience</span>
                                    <span className="rating-tag">★ {ca.rating}</span>
                                </div>
                            </div>
                            <div className="profile-actions">
                                <div className="price-tag">{ca.price}</div>
                                <button className="btn btn-primary" onClick={handleChat}>
                                    Chat with {ca.name.split(" ")[0]}
                                </button>
                            </div>
                        </div>
                    </div>

                    <div className="profile-details card">
                        <h2>About the Professional</h2>
                        <p>{ca.about}</p>

                        <div className="expertise-tags">
                            <h3>Core Expertise</h3>
                            <div className="tags">
                                <span className="tag">Taxation</span>
                                <span className="tag">Audit</span>
                                <span className="tag">Corporate Law</span>
                                <span className="tag">GST</span>
                            </div>
                        </div>
                    </div>

                    <div className="reviews-section card">
                        <h2>Client Reviews</h2>
                        <div className="reviews-list">
                            {ca.reviews && ca.reviews.length > 0 ? (
                                ca.reviews.map((review, index) => (
                                    <div key={index} className="review-item">
                                        <div className="review-header">
                                            <strong>{review.userName}</strong>
                                            <span className="review-stars">{"★".repeat(review.rating)}</span>
                                        </div>
                                        <p>{review.comment}</p>
                                        <small>{new Date(review.createdAt).toLocaleDateString()}</small>
                                    </div>
                                ))
                            ) : (
                                <p className="no-reviews">No reviews yet. Be the first to share your experience!</p>
                            )}
                        </div>
                    </div>
                </div>

                <aside className="profile-sidebar">
                    <div className="card sticky-card">
                        <h3>Quick Contact</h3>
                        <p>Need immediate assistance? Start a conversation now.</p>
                        <button className="btn btn-primary w-full" onClick={handleChat}>Message Now</button>
                    </div>
                </aside>
            </div>
        </div>
    );
}

export default CAProfile;
